function num(v) {
  if (v === null || v === undefined || v === "." || v === "") return null;
  const cleaned = String(v).replace("%", "").replace(",", ".").trim();
  const n = Number(cleaned);
  return Number.isFinite(n) ? n : null;
}

function getNode(name) {
  try {
    return $(name).first().json;
  } catch (error) {
    return null;
  }
}

function getNodeAll(name) {
  try {
    return $(name).all().map(item => item.json);
  } catch (error) {
    return [];
  }
}

function fredLatest(data) {
  const obs = data?.observations || [];
  const valid = obs.filter(o => num(o.value) !== null);
  const latest = num(valid[0]?.value);

  return {
    latest,
    d1: valid[1] && latest !== null ? latest - num(valid[1].value) : null,
    d5: valid[5] && latest !== null ? latest - num(valid[5].value) : null,
    d20: valid[20] && latest !== null ? latest - num(valid[20].value) : null,
    date: valid[0]?.date || null
  };
}

function fredPct(data) {
  const obs = data?.observations || [];
  const valid = obs.filter(o => num(o.value) !== null);
  const latest = num(valid[0]?.value);

  function pct(i) {
    const old = num(valid[i]?.value);
    if (latest === null || old === null || old === 0) return null;
    return ((latest - old) / old) * 100;
  }

  return {
    latest,
    d1: pct(1),
    d5: pct(5),
    d20: pct(20),
    date: valid[0]?.date || null
  };
}

function bundesbankCsvLatest(data) {
  const text = data?.data || "";
  const rows = String(text)
    .split("\n")
    .map(line => line.trim())
    .filter(line => /^\d{4}-\d{2}-\d{2};/.test(line))
    .map(line => {
      const parts = line.split(";");
      return { date: parts[0], value: num(parts[1]) };
    })
    .filter(row => row.value !== null)
    .reverse();

  const latest = rows[0]?.value ?? null;

  return {
    latest,
    d1: rows[1] && latest !== null ? latest - rows[1].value : null,
    d5: rows[5] && latest !== null ? latest - rows[5].value : null,
    d20: rows[20] && latest !== null ? latest - rows[20].value : null,
    date: rows[0]?.date || null
  };
}

function coinbasePrice(data) {
  return num(data?.data?.amount);
}

function alphaQuote(data) {
  const q = data?.["Global Quote"] || {};
  return {
    price: num(q["05. price"]),
    d1_pct: num(q["10. change percent"])
  };
}

function pctChange(current, old) {
  current = num(current);
  old = num(old);
  if (current === null || old === null || old === 0) return null;
  return ((current - old) / old) * 100;
}

function bps(v) {
  return v !== null && v !== undefined ? v * 100 : null;
}

function spread(a, b) {
  return a !== null && b !== null ? a - b : null;
}

function spreadD5(a, b) {
  if (a?.latest === null || b?.latest === null || a?.d5 === null || b?.d5 === null) return null;
  const spreadNow = a.latest - b.latest;
  const spread5dAgo = (a.latest - a.d5) - (b.latest - b.d5);
  return (spreadNow - spread5dAgo) * 100;
}

const now = new Date();
const today = now.toISOString().slice(0, 10);

const previousRows = getNodeAll("Supabase | Get Previous Market Snapshots")
  .filter(r => r.snapshot_date && r.run_time_et)
  .filter(r => r.snapshot_date < today)
  .sort((a, b) => new Date(b.run_time_et) - new Date(a.run_time_et));

const uniquePreviousRows = [];
const seenDates = new Set();

for (const row of previousRows) {
  if (!seenDates.has(row.snapshot_date)) {
    uniquePreviousRows.push(row);
    seenDates.add(row.snapshot_date);
  }
}

function historyPct(current, field, index) {
  const oldRow = uniquePreviousRows[index];
  return oldRow ? pctChange(current, oldRow[field]) : null;
}

const us2yRaw = getNode("HTTP Request | US 2Y Treasury Yield - FRED API");
const us10yRaw = getNode("HTTP Request | US 10Y Treasury Yield - FRED Api");
const tips10yRaw = getNode("HTTP Request | TIPS 10Y Real Yield - FRED Api");
const de2yRaw = getNode("HTTP Request | Germany 2Y Yield");
const de10yRaw = getNode("HTTP Request | Germany 10Y Proxy - FRED Api");
const uk10yRaw = getNode("HTTP Request | UK 10Y Proxy - FRED api");
const jp10yRaw = getNode("HTTP Request | Japan 10Y Proxy - FRED API");

const vixRaw = getNode("HTTP Request | VIX - FRED Api");
const dxyRaw = getNode("HTTP Request | DXY - FRED Dollar Index - FRED API");
const goldRaw = getNode("HTTP Request | Gold - Coinbase");
const btcRaw = getNode("HTTP Request | BTC - Coinbase");
const wtiRaw = getNode("HTTP Request | WTI Oil - FRED Api");
const brentRaw = getNode("HTTP Request | Brent Oil - FRED Api");

const jpyUsdRaw = getNode("HTTP Request | USD/JPY - Coinbase");
const gbpUsdRaw = getNode("HTTP Request | GBP/USD - Coinbase");
const cadUsdRaw = getNode("HTTP Request | USD/CAD - Coinbase");
const audUsdRaw = getNode("HTTP Request | AUD/USD - Coinbase");
const eurusdRaw = getNode("HTTP Request | EURUSD - FRED API");
const nqRaw = getNode("HTTP Request | NQ - Alpha Vantage");

const usEcoDataRaw = getNode("Code | Derive US Eco Inputs");

const us2y = fredLatest(us2yRaw);
const us10y = fredLatest(us10yRaw);
const tips10y = fredLatest(tips10yRaw);
const de2y = bundesbankCsvLatest(de2yRaw);
const de10y = fredLatest(de10yRaw);
const uk10y = fredLatest(uk10yRaw);
const jp10y = fredLatest(jp10yRaw);
const vix = fredLatest(vixRaw);
const dxy = fredPct(dxyRaw);

const goldPrice = coinbasePrice(goldRaw);
const btcPrice = coinbasePrice(btcRaw);

const goldD1Pct = historyPct(goldPrice, "gold_price", 0);
const goldD5Pct = historyPct(goldPrice, "gold_price", 4);
const goldD20Pct = historyPct(goldPrice, "gold_price", 19);

const btcD1Pct = historyPct(btcPrice, "btc_price", 0);
const btcD5Pct = historyPct(btcPrice, "btc_price", 4);
const btcD20Pct = historyPct(btcPrice, "btc_price", 19);

const wti = fredPct(wtiRaw);
const brent = fredPct(brentRaw);

const jpyUsd = coinbasePrice(jpyUsdRaw);
const gbpUsd = coinbasePrice(gbpUsdRaw);
const cadUsd = coinbasePrice(cadUsdRaw);
const audUsd = coinbasePrice(audUsdRaw);

const eurusd = fredPct(eurusdRaw);
const nq = alphaQuote(nqRaw);

const nqD1Pct = nq.d1_pct ?? historyPct(nq.price, "nq_price", 0);
const nqD5Pct = historyPct(nq.price, "nq_price", 4);
const nqD20Pct = historyPct(nq.price, "nq_price", 19);

const latestUsEvent = usEcoDataRaw?.latest_us_event || null;

const upcomingEvents = Array.isArray(usEcoDataRaw?.upcoming_us_events)
  ? usEcoDataRaw.upcoming_us_events
  : [];

const fedBias = usEcoDataRaw?.fed_bias || "unknown";

const usDe2ySpread = spread(us2y.latest, de2y.latest);
const usDe2ySpreadD5Bps = spreadD5(us2y, de2y);

const usDe10ySpread = spread(us10y.latest, de10y.latest);
const usJp10ySpread = spread(us10y.latest, jp10y.latest);

const equitiesRegime =
  vix.latest !== null && vix.latest < 16 ? "risk_on" :
  vix.latest !== null && vix.latest > 25 ? "risk_off" :
  "neutral";

const globalGrowthRegime =
  nqD20Pct !== null && nqD20Pct > 5 ? "expanding" :
  nqD20Pct !== null && nqD20Pct < -5 ? "contracting" :
  "neutral";

const missing = [];

function checkMissing(label, value) {
  if (value === null || value === undefined) missing.push(label);
}

checkMissing("vix_level", vix.latest);
checkMissing("vix_d1", vix.d1);
checkMissing("vix_d5", vix.d5);

checkMissing("dxy_level", dxy.latest);
checkMissing("dxy_d1", dxy.d1);
checkMissing("dxy_d5", dxy.d5);
checkMissing("dxy_d20", dxy.d20);

checkMissing("us_10y_yield", us10y.latest);
checkMissing("us_10y_d5_bps", bps(us10y.d5));
checkMissing("us_10y_d20_bps", bps(us10y.d20));

checkMissing("us_10y_real_yield", tips10y.latest);
checkMissing("us_10y_real_yield_d5_bps", bps(tips10y.d5));
checkMissing("us_10y_real_yield_d20_bps", bps(tips10y.d20));

checkMissing("gold_price", goldPrice);
checkMissing("gold_d1_pct", goldD1Pct);
checkMissing("gold_d5_pct", goldD5Pct);
checkMissing("gold_d20_pct", goldD20Pct);

checkMissing("btc_price", btcPrice);
checkMissing("btc_d1_pct", btcD1Pct);
checkMissing("btc_d5_pct", btcD5Pct);
checkMissing("btc_d20_pct", btcD20Pct);

checkMissing("nq_price", nq.price);
checkMissing("nq_d1_pct", nqD1Pct);
checkMissing("nq_d5_pct", nqD5Pct);
checkMissing("nq_d20_pct", nqD20Pct);

checkMissing("latest_us_event", latestUsEvent);
checkMissing("fed_bias", fedBias === "unknown" ? null : fedBias);

const row = {
  snapshot_date: today,
  run_time_et: now.toISOString(),
  source_status: missing.length ? "partial" : "collected",
  collector_version: "nq_v2_economic_events_weighted_inputs",

  vix_level: vix.latest,
  vix_d1: vix.d1,
  vix_d5: vix.d5,

  dxy_level: dxy.latest,
  dxy_d1: dxy.d1,
  dxy_d5: dxy.d5,
  dxy_d20: dxy.d20,

  us_2y_yield: us2y.latest,
  us_2y_d5_bps: bps(us2y.d5),
  us_2y_d20_bps: bps(us2y.d20),

  de_2y_yield: de2y.latest,
  de_2y_d5_bps: bps(de2y.d5),

  us_de_2y_spread: usDe2ySpread,
  us_de_2y_spread_d5_bps: usDe2ySpreadD5Bps,

  us_10y_yield: us10y.latest,
  us_10y_d5_bps: bps(us10y.d5),
  us_10y_d20_bps: bps(us10y.d20),

  us_10y_real_yield: tips10y.latest,
  us_10y_real_yield_d5_bps: bps(tips10y.d5),
  us_10y_real_yield_d20_bps: bps(tips10y.d20),

  gold_price: goldPrice,
  gold_d1_pct: goldD1Pct,
  gold_d5_pct: goldD5Pct,
  gold_d20_pct: goldD20Pct,

  nq_price: nq.price,
  nq_d1_pct: nqD1Pct,
  nq_d5_pct: nqD5Pct,
  nq_d20_pct: nqD20Pct,

  btc_price: btcPrice,
  btc_d1_pct: btcD1Pct,
  btc_d5_pct: btcD5Pct,
  btc_d20_pct: btcD20Pct,

  btc_dominance: null,

  spx_d1_pct: null,
  equities_regime: equitiesRegime,

  latest_us_event: latestUsEvent,
  latest_ez_event: null,
  upcoming_events: upcomingEvents,

  fed_bias: fedBias,
  ecb_bias: null,

  global_growth_regime: globalGrowthRegime,
  ez_stress_flag: null,
  geopolitical_risk_flag: null,

  data_quality: {
    collector_status: missing.length ? "partial" : "complete",
    missing,
    history_rows_used: uniquePreviousRows.length,

    us_events_found: usEcoDataRaw?.data_quality?.us_events_found || 0,
    recent_us_events_found: usEcoDataRaw?.data_quality?.completed_us_events_found || 0,
    upcoming_us_events_found: usEcoDataRaw?.data_quality?.upcoming_us_events_found || 0,
    fed_bias_model_status: usEcoDataRaw ? "connected" : "missing",
    global_growth_model_status: globalGrowthRegime ? "connected" : "missing",

    notes: [
      "NQ Layer 1 may read this row, but must not read other agent outputs.",
      "NQ collector now reads US economic events from Supabase economic_events via Code | Derive US Eco Inputs.",
      "Gold d1/d5/d20, BTC d1/d5/d20 and NQ d1/d5/d20 are calculated from Alpha Vantage/Supabase market_snapshots.",
      "NQ d1_pct uses Alpha Vantage first, then falls back to previous Supabase market_snapshots.",
      "Fed bias is derived from structured US economic event surprise data.",
      "Global growth regime is derived from NQ 20-day trend.",
      "Layer 1 isolation remains intact because this row contains only raw market snapshot fields, not other agent outputs."
    ]
  },

  raw_payload: {
    previous_snapshot_dates_used: uniquePreviousRows.map(r => r.snapshot_date),

    us_eco_data: usEcoDataRaw,
    fed_bias_model: {
      fed_bias: fedBias,
      fed_bias_score: usEcoDataRaw?.fed_bias_score ?? 0,
      fed_bias_reasons: usEcoDataRaw?.fed_bias_reasons || []
    },

    us2y,
    us10y,
    tips10y,
    de2y,
    de10y,
    uk10y,
    jp10y,
    vix,
    dxy,
    goldPrice,
    btcPrice,
    wti,
    brent,
    jpyUsd,
    gbpUsd,
    cadUsd,
    audUsd,
    eurusd,
    nq,

    proxy_spreads: {
      us_de_2y_spread: usDe2ySpread,
      us_de_2y_spread_d5_bps: usDe2ySpreadD5Bps,
      us_de_10y_spread: usDe10ySpread,
      us_jp_10y_spread: usJp10ySpread
    }
  }
};

return [{ json: row }];

const recent   = $('HTTP Request | Eco Calendar Recent - Finnhub').first().json.economicCalendar;
const upcoming = $('HTTP Request | Eco Calendar Upcoming - Finnhub').first().json.economicCalendar;

// Tier-1 US indicators with sigma values for surprise normalisation
const TIER1 = {
  'Non Farm Payrolls':          { key: 'NFP',           sigma: 80 },
  'Average Hourly Earnings MoM':{ key: 'AHE_MOM',       sigma: 0.1 },
  'Unemployment Rate':          { key: 'UNEMPLOYMENT',  sigma: 0.15 },
  'Core Inflation Rate MoM':    { key: 'CORE_CPI_MOM',  sigma: 0.1 },
  'Inflation Rate MoM':         { key: 'CPI_MOM',       sigma: 0.15 },
  'ISM Manufacturing PMI':      { key: 'ISM_MFG',       sigma: 2.5 },
  'ISM Services PMI':           { key: 'ISM_SVCS',      sigma: 2.5 },
  'GDP Growth Rate QoQ Adv':    { key: 'GDP_ADV',       sigma: 0.5 },
  'ADP Employment Change':      { key: 'ADP',           sigma: 50 },
  'Initial Jobless Claims':     { key: 'JOBLESS_CLAIMS',sigma: 15 },
  'JOLTs Job Openings':         { key: 'JOLTS',         sigma: 0.3 }
};

// Filter recent US high/medium impact events with actuals
const recentUS = (recent || []).filter(e =>
  e.country === 'US' &&
  ['high','medium'].includes(e.impact) &&
  e.actual !== null
);

// Filter upcoming US high/medium impact events without actuals
const upcomingUS = (upcoming || []).filter(e =>
  e.country === 'US' &&
  ['high','medium'].includes(e.impact) &&
  e.actual === null
);

// Compute surprise scores for tier-1 recent prints
const surprises = [];
for (const event of recentUS) {
  const tier1 = TIER1[event.event];
  if (!tier1) continue;
  if (event.actual === null || event.estimate === null) continue;
  const surprise = (event.actual - event.estimate) / tier1.sigma;
  surprises.push({
    key:       tier1.key,
    event:     event.event,
    date:      event.time.split(' ')[0],
    actual:    event.actual,
    estimate:  event.estimate,
    surprise:  Math.round(surprise * 100) / 100,
    direction: surprise > 0 ? 'BEAT' : surprise < 0 ? 'MISS' : 'IN LINE'
  });
}

// Format upcoming calendar
const calendar = upcomingUS.map(e => ({
  event:    e.event,
  time:     e.time,
  estimate: e.estimate,
  impact:   e.impact
}));

// Format recent all US high/medium events (not just tier-1) for prompt context
const recentSummary = recentUS.slice(-20).map(e => ({
  event:    e.event,
  time:     e.time.split(' ')[0],
  actual:   e.actual,
  estimate: e.estimate,
  prev:     e.prev,
  impact:   e.impact
}));

return [{
  json: {
    surprises,
    calendar,
    recentSummary
  }
}];

const eco = $('Code | Process Eco Data').first().json;

const surprises = eco.surprises || [];

let score = 0;
const reasons = [];

for (const s of surprises) {
  if (s.direction === "BEAT") {
    score += 1;
    reasons.push(`${s.event} beat forecast`);
  }

  if (s.direction === "MISS") {
    score -= 1;
    reasons.push(`${s.event} missed forecast`);
  }
}

let fed_bias = "neutral";

if (score >= 2) fed_bias = "hawkish";
if (score <= -2) fed_bias = "dovish";

return [
  {
    json: {
      fed_bias,
      fed_bias_score: score,
      fed_bias_reasons: reasons.slice(0, 5)
    }
  }
];

function impactRank(impact) {
  const s = String(impact || '').toLowerCase();
  if (s.includes('high')) return 3;
  if (s.includes('medium')) return 2;
  if (s.includes('low')) return 1;
  return 0;
}

function priority(name) {
  const n = String(name || '').toLowerCase();

  if (n.includes('non farm') || n.includes('nfp')) return 100;
  if (n.includes('cpi') || n.includes('inflation')) return 98;
  if (n.includes('fomc') || n.includes('fed')) return 96;
  if (n.includes('ism')) return 94;
  if (n.includes('pmi')) return 90;
  if (n.includes('gdp')) return 88;
  if (n.includes('unemployment')) return 85;
  if (n.includes('average hourly')) return 82;
  if (n.includes('jobless')) return 78;
  if (n.includes('jolts')) return 75;
  if (n.includes('retail sales')) return 72;

  return 50;
}

function eventTimestamp(e) {
  const date = e.event_date || e.date || '';
  const time = e.event_time_text || e.time || '00:00';
  const cleanTime = String(time).replace(/am/i, ' AM').replace(/pm/i, ' PM');
  const parsed = new Date(`${date} ${cleanTime}`);
  return Number.isFinite(parsed.getTime()) ? parsed.getTime() : 0;
}

function eventKey(e) {
  return [
    e.event_date || '',
    e.event_time_text || '',
    e.currency || '',
    e.event_name || ''
  ].join('|').toLowerCase();
}

const rawEvents = $input.all().map(i => i.json);

const seen = new Set();
const events = [];

for (const e of rawEvents) {
  const key = eventKey(e);
  if (seen.has(key)) continue;
  seen.add(key);
  events.push(e);
}

const completed = events
  .filter(e => e.actual !== null && e.actual !== undefined && e.actual !== '')
  .map(e => ({
    event: e.event_name,
    actual: e.actual,
    forecast: e.forecast,
    previous: e.previous,
    surprise: e.surprise_direction,
    usd_signal: e.currency_signal,
    surprise_score: e.surprise_score ?? null,
    date: e.event_date,
    time: e.event_time_text,
    impact: e.impact,
    priority: priority(e.event_name),
    impact_rank: impactRank(e.impact),
    raw: e,
    timestamp: eventTimestamp(e)
  }))
  .sort((a, b) => {
    const timeDiff = b.timestamp - a.timestamp;
    if (timeDiff !== 0) return timeDiff;

    const impactDiff = b.impact_rank - a.impact_rank;
    if (impactDiff !== 0) return impactDiff;

    return b.priority - a.priority;
  });

const upcoming_us_events = events
  .filter(e => e.actual === null || e.actual === undefined || e.actual === '')
  .map(e => ({
    event: e.event_name,
    forecast: e.forecast,
    previous: e.previous,
    date: e.event_date,
    time: e.event_time_text,
    impact: e.impact,
    priority: priority(e.event_name),
    impact_rank: impactRank(e.impact),
    timestamp: eventTimestamp(e)
  }))
  .sort((a, b) => {
    const timeDiff = a.timestamp - b.timestamp;
    if (timeDiff !== 0) return timeDiff;

    const impactDiff = b.impact_rank - a.impact_rank;
    if (impactDiff !== 0) return impactDiff;

    return b.priority - a.priority;
  })
  .slice(0, 10);

const latest_us_event = completed[0] || null;

let fed_bias_score = 0;
const fed_bias_reasons = [];

for (const e of completed.slice(0, 8)) {
  const signal = String(e.usd_signal || '').toUpperCase();
  const weight = e.impact_rank >= 3 ? 2 : 1;

  if (signal === 'BULLISH') {
    fed_bias_score += weight;
    fed_bias_reasons.push(`${e.event} beat forecast`);
  }

  if (signal === 'BEARISH') {
    fed_bias_score -= weight;
    fed_bias_reasons.push(`${e.event} missed forecast`);
  }
}

let fed_bias = 'neutral';
if (fed_bias_score >= 2) fed_bias = 'hawkish';
if (fed_bias_score <= -2) fed_bias = 'dovish';

return [{
  json: {
    latest_us_event,
    upcoming_us_events,
    fed_bias,
    fed_bias_score,
    fed_bias_reasons,
    recentUsSummary: completed,
    usCalendar: upcoming_us_events,
    source: 'economic_events',
    data_quality: {
      raw_us_events_found: rawEvents.length,
      deduped_us_events_found: events.length,
      completed_us_events_found: completed.length,
      upcoming_us_events_found: upcoming_us_events.length
    }
  }
}];
